/**
 * TimelineHeader - Displays date labels synced with canvas panX
 *
 * Features:
 * - Adaptive granularity based on zoom level:
 *   - Low zoom (< 0.5): Years
 *   - Medium zoom (0.5-1.5): Months
 *   - High zoom (1.5-3.0): Weeks
 *   - Very high zoom (> 3.0): Days
 * - Labels positioned to align with canvas content
 * - Labels don't overlap (spacing adjusted based on zoom)
 *
 * D3-MIGRATE-001: Uses d3-time and d3-time-format for date operations
 */

import { useMemo } from 'react';
import { timeYear, timeMonth, timeWeek, timeDay } from 'd3-time';
import { timeFormat } from 'd3-time-format';
import { DEFAULT_VIEW_CONFIG, DEFAULT_DATASET_META } from '../data/types';

interface TimelineHeaderProps {
  /** Left edge of the visible viewport in world X coordinates */
  viewportLeftX: number;
  /** Right edge of the visible viewport in world X coordinates */
  viewportRightX: number;
  /** Current zoom level */
  zoom: number;
  /** Width of the sidebar (to offset the timeline) */
  sidebarWidth: number;
  /** Callback when a date label is clicked (F124: navigation) */
  onDateClick?: (dayOffset: number) => void;
}

const { pxPerDay } = DEFAULT_VIEW_CONFIG;
const START_DATE = new Date(DEFAULT_DATASET_META.startDate);

// D3-MIGRATE-001: Format helpers using d3-time-format
const formatYear = timeFormat('%Y');
const formatMonth = timeFormat('%b %Y');
const formatWeek = timeFormat('%b %d');
const formatDay = timeFormat('%a, %b %d');

/**
 * Calculate the appropriate granularity based on zoom level
 */
type Granularity = 'year' | 'month' | 'week' | 'day';

function getGranularity(zoom: number): Granularity {
  if (zoom < 0.5) return 'year';
  if (zoom < 1.5) return 'month';
  if (zoom < 3.0) return 'week';
  return 'day';
}

/**
 * Get the minimum pixel spacing between labels for each granularity
 */
function getMinLabelSpacing(granularity: Granularity): number {
  switch (granularity) {
    case 'year':
      return 80;
    case 'month':
      return 70;
    case 'week':
      return 60;
    case 'day':
      return 50;
  }
}

/**
 * Convert world X coordinate to day offset from start date
 */
function worldXToDayOffset(worldX: number): number {
  return Math.floor(worldX / pxPerDay);
}

/**
 * Convert day offset to world X coordinate
 */
function dayOffsetToWorldX(dayOffset: number): number {
  return dayOffset * pxPerDay;
}

// D3-MIGRATE-001: Time interval map for granularity-based operations
const timeIntervals = {
  year: timeYear,
  month: timeMonth,
  week: timeWeek,
  day: timeDay,
} as const;

/**
 * Add days to a date (D3-MIGRATE-001: uses d3-time)
 */
function addDays(date: Date, days: number): Date {
  return timeDay.offset(date, days);
}

/**
 * Get the start of a time unit (D3-MIGRATE-001: uses d3-time floor)
 */
function getUnitStart(date: Date, granularity: Granularity): Date {
  return timeIntervals[granularity].floor(date);
}

/**
 * Get days until next unit
 */
function getDaysPerUnit(granularity: Granularity): number {
  switch (granularity) {
    case 'year':
      return 365;
    case 'month':
      return 30;
    case 'week':
      return 7;
    case 'day':
      return 1;
  }
}

/**
 * Advance to next unit (D3-MIGRATE-001: uses d3-time offset)
 */
function advanceUnit(date: Date, granularity: Granularity): Date {
  return timeIntervals[granularity].offset(date, 1);
}

/**
 * Format date based on granularity
 */
function formatDate(date: Date, granularity: Granularity): string {
  switch (granularity) {
    case 'year':
      return formatYear(date);
    case 'month':
      return formatMonth(date);
    case 'week':
      return formatWeek(date);
    case 'day':
      return formatDay(date);
  }
}

interface TimeLabel {
  dayOffset: number;
  worldX: number;
  label: string;
  isMinor: boolean; // For smaller tick marks
}

/**
 * Generate labels for the visible viewport
 */
function generateLabels(
  viewportLeftX: number,
  viewportRightX: number,
  granularity: Granularity
): TimeLabel[] {
  const labels: TimeLabel[] = [];

  // Add padding to viewport to show labels near edges
  const padding = getDaysPerUnit(granularity) * pxPerDay * 2;
  const startDayOffset = worldXToDayOffset(viewportLeftX - padding);
  const endDayOffset = worldXToDayOffset(viewportRightX + padding);

  // Convert to dates
  const startDate = addDays(START_DATE, startDayOffset);
  const endDate = addDays(START_DATE, endDayOffset);

  // Find the first unit boundary at or before startDate
  let currentDate = getUnitStart(startDate, granularity);

  // If currentDate is before START_DATE, advance to START_DATE
  if (currentDate < START_DATE) {
    currentDate = getUnitStart(START_DATE, granularity);
    if (currentDate < START_DATE) {
      currentDate = advanceUnit(currentDate, granularity);
    }
  }

  // Generate labels until we pass endDate
  while (currentDate <= endDate) {
    const dayOffset = Math.round(
      (currentDate.getTime() - START_DATE.getTime()) / (1000 * 60 * 60 * 24)
    );
    const worldX = dayOffsetToWorldX(dayOffset);

    // Only add labels within reasonable range
    if (worldX >= viewportLeftX - padding && worldX <= viewportRightX + padding) {
      labels.push({
        dayOffset,
        worldX,
        label: formatDate(currentDate, granularity),
        isMinor: false,
      });
    }

    currentDate = advanceUnit(currentDate, granularity);
  }

  return labels;
}

export function TimelineHeader({
  viewportLeftX,
  viewportRightX,
  zoom,
  sidebarWidth,
  onDateClick,
}: TimelineHeaderProps) {
  const granularity = useMemo(() => getGranularity(zoom), [zoom]);

  const labels = useMemo(
    () => generateLabels(viewportLeftX, viewportRightX, granularity),
    [viewportLeftX, viewportRightX, granularity]
  );

  // Calculate viewport width with defensive check
  const viewportWidth = viewportRightX - viewportLeftX;

  // BUG-005: Guard against invalid viewport (e.g., during initialization)
  const isViewportValid = isFinite(viewportWidth) && viewportWidth > 0;

  return (
    <div
      style={{
        height: 32,
        backgroundColor: '#f5f8fa',
        borderBottom: '1px solid #e1e8ed',
        display: 'flex',
        alignItems: 'center',
        overflow: 'hidden',
        position: 'relative',
        marginLeft: sidebarWidth,
      }}
    >
      {isViewportValid && labels.map((label, index) => {
        // Calculate position as percentage of viewport
        const positionInViewport = label.worldX - viewportLeftX;
        const percentPosition = (positionInViewport / viewportWidth) * 100;

        // BUG-005: Skip labels that would be too far off screen
        // Use wider bounds for year granularity since labels are spaced far apart
        const skipMargin = granularity === 'year' ? 50 : 20;
        if (!isFinite(percentPosition) || percentPosition < -skipMargin || percentPosition > 100 + skipMargin) {
          return null;
        }

        // BUG-005: Adjust transform for edge labels to keep them visible
        // At edges, don't center the label - align it to stay within bounds
        let transformX = '-50%';  // Default: center on position
        if (percentPosition < 5) {
          // Near left edge: align left edge to position
          transformX = '0%';
        } else if (percentPosition > 95) {
          // Near right edge: align right edge to position
          transformX = '-100%';
        }

        return (
          <div
            key={`${label.label}-${index}`}
            onClick={() => onDateClick?.(label.dayOffset)}
            style={{
              position: 'absolute',
              left: `${percentPosition}%`,
              transform: `translateX(${transformX})`,
              fontSize: 11,
              fontFamily: 'monospace',
              color: '#5c7080',
              whiteSpace: 'nowrap',
              padding: '4px 8px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              cursor: onDateClick ? 'pointer' : 'default',
              borderRadius: 4,
              transition: 'background-color 0.15s ease, color 0.15s ease',
              zIndex: 2, // BUG-005: Ensure labels are above gradient overlays
              backgroundColor: '#f5f8fa', // BUG-005: Add background so labels are readable over gradients
            }}
            onMouseEnter={(e) => {
              if (onDateClick) {
                e.currentTarget.style.backgroundColor = '#e1e8ed';
                e.currentTarget.style.color = '#1c2127';
              }
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = 'transparent';
              e.currentTarget.style.color = '#5c7080';
            }}
            title={onDateClick ? `Click to navigate to ${label.label}` : undefined}
          >
            <span>{label.label}</span>
            <div
              style={{
                width: 1,
                height: 6,
                backgroundColor: '#d8e1e8',
                marginTop: 2,
              }}
            />
          </div>
        );
      })}

      {/* Gradient overlays to fade labels at edges - z-index 1 so labels (z-index 2) are above */}
      <div
        style={{
          position: 'absolute',
          left: 0,
          top: 0,
          bottom: 0,
          width: 20, // BUG-005: Reduced from 30 to leave more space for labels
          background: 'linear-gradient(to right, #f5f8fa, transparent)',
          pointerEvents: 'none',
          zIndex: 1,
        }}
      />
      <div
        style={{
          position: 'absolute',
          right: 0,
          top: 0,
          bottom: 0,
          width: 20, // BUG-005: Reduced from 30 to leave more space for labels
          background: 'linear-gradient(to left, #f5f8fa, transparent)',
          pointerEvents: 'none',
          zIndex: 1,
        }}
      />
    </div>
  );
}

