  1725→        pointerDownPosRef.current = { x: e.clientX, y: e.clientY };
  1726→        pointerMovedRef.current = false;
  1727→
  1728→        // Start pan in store
  1729→        canvasStore.dispatch(
  1730→          canvasActions.viewport.startPan({
  1731→            panStart: { x: e.clientX, y: e.clientY },
  1732→            cameraPosAtPanStart: currentCamera,
  1733→          })
  1734→        );
  1735→
  1736→        // Initialize velocity tracking
  1737→        const now = performance.now();
  1738→        lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1739→        velocitySamplesRef.current = [];
  1740→      }
  1741→
  1742→      (e.target as HTMLElement).setPointerCapture(e.pointerId);
  1743→    },
  1744→    [zoom, isInitialized, stopMomentum, stopZoomAnimation]
  1745→  );
  1746→
  1747→  /**
  1748→   * Handle hover detection (F018)
  1749→   * Updates hovered task based on mouse position
  1750→   */
  1751→  const updateHover = useCallback(
  1752→    (e: React.PointerEvent) => {
  1753→      // Only update hover when not panning (avoid expensive calculations during drag)
  1754→      const state = canvasStore.getState();
  1755→      if (state.viewport.isPanning) {
  1756→        // Clear hover during panning
  1757→        if (state.interaction.hoveredTaskId !== null) {
  1758→          canvasStore.dispatch(canvasActions.interaction.setHoveredTask(null));
  1759→        }
  1760→        return;
  1761→      }
  1762→
  1763→      // Get container rect for coordinate conversion
  1764→      const container = containerRef.current;
  1765→      if (!container) return;
  1766→
  1767→      const rect = container.getBoundingClientRect();
  1768→      const camera = state.viewport.camera;
  1769→
  1770→      // Find task under cursor
  1771→      const taskId = findTaskAtPosition(
  1772→        e.clientX,
  1773→        e.clientY,
  1774→        rect,
  1775→        camera.x,
  1776→        camera.y,
  1777→        zoom,
  1778→        canvasSize.width,
  1779→        canvasSize.height,
  1780→        tasks
  1781→      );
  1782→
  1783→      // Only update if changed (avoid unnecessary state updates)
  1784→      if (taskId !== state.interaction.hoveredTaskId) {
  1785→        canvasStore.dispatch(canvasActions.interaction.setHoveredTask(taskId));
  1786→      }
  1787→    },
  1788→    [zoom, canvasSize, tasks]
  1789→  );
  1790→
  1791→  /**
  1792→   * Handle pan move / pinch move
  1793→   *
  1794→   * Now uses canvasStore for pan state - values always current
  1795→   */
  1796→  const handlePointerMove = useCallback(
  1797→    (e: React.PointerEvent) => {
  1798→      const pinch = pinchRef.current;
  1799→
  1800→      // Update pointer position
  1801→      if (pinch.pointers.has(e.pointerId)) {
  1802→        pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1803→      }
  1804→
  1805→      // Handle pinch gesture
  1806→      if (pinch.active && pinch.pointers.size === 2) {
  1807→        const pointers = Array.from(pinch.pointers.values());
  1808→        const dx = pointers[0].x - pointers[1].x;
  1809→        const dy = pointers[0].y - pointers[1].y;
  1810→        const currentDistance = Math.sqrt(dx * dx + dy * dy);
  1811→
  1812→        if (pinch.initialDistance > 0) {
  1813→          const scale = currentDistance / pinch.initialDistance;
  1814→          const centerX = (pointers[0].x + pointers[1].x) / 2;
  1815→          const centerY = (pointers[0].y + pointers[1].y) / 2;
  1816→          handlePinchZoom(scale, centerX, centerY);
  1817→        }
  1818→        return;
  1819→      }
  1820→
  1821→      // Update hover state (F018) - always run to update cursor
  1822→      updateHover(e);
  1823→
  1824→      // Handle pan - get current state from store
  1825→      const state = canvasStore.getState();
  1826→      if (!state.viewport.isPanning) return;
  1827→
  1828→      const dx = (e.clientX - state.viewport.panStart.x) / zoom;
  1829→      const dy = (e.clientY - state.viewport.panStart.y) / zoom;
  1830→
  1831→      // Detect significant movement (F019: to distinguish click from pan)
  1832→      // Using 8px threshold - movement greater than this is a pan, not a click
  1833→      // Higher threshold helps with touchpad/mouse precision issues
  1834→      const moveX = e.clientX - pointerDownPosRef.current.x;
  1835→      const moveY = e.clientY - pointerDownPosRef.current.y;
  1836→      const moveDistance = Math.sqrt(moveX * moveX + moveY * moveY);
  1837→      if (moveDistance > 8) {
  1838→        pointerMovedRef.current = true;
  1839→      }
  1840→
  1841→      const newX = state.viewport.cameraPosAtPanStart.x - dx;
  1842→      const newY = state.viewport.cameraPosAtPanStart.y + dy;
  1843→
  1844→      const clamped = clampCameraToWorld(newX, newY, zoom);
  1845→
  1846→      // Update pan in store
  1847→      canvasStore.dispatch(canvasActions.viewport.updatePan({ camera: clamped }));
  1848→      notifyViewportChange(clamped.x, clamped.y, zoom);
  1849→
  1850→      // Track velocity samples for momentum
  1851→      const now = performance.now();
  1852→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
  1853→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
  1854→
  1855→      velocitySamplesRef.current.push({
  1856→        x: worldDx,
  1857→        y: worldDy,
  1858→        time: now,
  1859→      });
  1860→
  1861→      // Keep only recent samples
  1862→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
  1863→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
  1864→      }
  1865→
  1866→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1867→    },
  1868→    [zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom, updateHover]
  1869→  );
  1870→
  1871→  /**
  1872→   * Handle pan end / pinch end
  1873→   *
  1874→   * Now uses canvasStore for pan state
  1875→   */
  1876→  const handlePointerUp = useCallback(
  1877→    (e: React.PointerEvent) => {
  1878→      const pinch = pinchRef.current;
  1879→
  1880→      // Remove pointer from tracking
  1881→      pinch.pointers.delete(e.pointerId);
  1882→
  1883→      // Release pointer capture
  1884→      try {
  1885→        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  1886→      } catch {
  1887→        // Ignore if capture was already released
  1888→      }
  1889→
  1890→      // Reset pinch state when all pointers released
  1891→      if (pinch.pointers.size < 2) {
  1892→        pinch.active = false;
  1893→        pinch.initialDistance = 0;
  1894→      }
  1895→
  1896→      // Handle pan end with momentum - check store for isPanning
  1897→      const state = canvasStore.getState();
  1898→      if (state.viewport.isPanning && pinch.pointers.size === 0) {
  1899→        canvasStore.dispatch(canvasActions.viewport.endPan());
  1900→
  1901→        // BUG-008: Momentum disabled - was causing elastic/jumping behavior
  1902→        // The momentum animation had stale closure issues despite the cameraPosRef fix
  1903→        // TODO: Reimplement with proper state synchronization if momentum UX is desired
  1904→        // Original code:
  1905→        // const { vx, vy } = calculateAverageVelocity();
  1906→        // const speed = Math.sqrt(vx ** 2 + vy ** 2);
  1907→        // if (speed > 0.01) { startMomentum(vx, vy); }
  1908→      }
  1909→    },
  1910→    [calculateAverageVelocity, startMomentum]
  1911→  );
  1912→
  1913→  /**
  1914→   * Handle double-click to zoom in at click location
  1915→   * Zooms 2x toward the clicked point with smooth animation
  1916→   *
  1917→   * Now uses animateZoomTo which uses the canvasStore
  1918→   */
  1919→  const handleDoubleClick = useCallback(
  1920→    (e: React.MouseEvent) => {
  1921→      if (!isInitialized) return;
  1922→
  1923→      // Stop any active animations
  1924→      stopMomentum();
  1925→      stopZoomAnimation();
  1926→
  1927→      const rect = containerRef.current?.getBoundingClientRect();
  1928→      if (!rect) return;
  1929→
  1930→      // Get current camera from store
  1931→      const currentCamera = canvasStore.getState().viewport.camera;
  1932→
  1933→      // Calculate target zoom (2x, clamped to MAX_ZOOM)
  1934→      const targetZoom = Math.min(zoom * 2, MAX_ZOOM);
  1935→      if (Math.abs(targetZoom - zoom) < 0.001) return;
  1936→
  1937→      // Cursor position relative to canvas center
  1938→      const cursorX = e.clientX - rect.left - rect.width / 2;
  1939→      const cursorY = e.clientY - rect.top - rect.height / 2;
  1940→
  1941→      // Calculate target camera position (zoom toward click point)
  1942→      const worldX = cursorX / zoom + currentCamera.x;
  1943→      const worldY = -cursorY / zoom + currentCamera.y;
  1944→      const newCameraX = worldX - cursorX / targetZoom;
  1945→      const newCameraY = worldY + cursorY / targetZoom;
  1946→
  1947→      const clamped = clampCameraToWorld(newCameraX, newCameraY, targetZoom);
  1948→
  1949→      // Animate with slightly longer duration for double-click (350ms)
  1950→      animateZoomTo(targetZoom, clamped.x, clamped.y, 350);
  1951→    },
  1952→    [zoom, isInitialized, stopMomentum, stopZoomAnimation, clampCameraToWorld, animateZoomTo]
  1953→  );
  1954→
  1955→  /**
  1956→   * Handle click to select/deselect task (F019)
  1957→   * Clicks on tasks select them, clicks on background deselect
  1958→   */
  1959→  const handleClick = useCallback(
  1960→    (e: React.MouseEvent) => {
  1961→      if (!isInitialized) return;
  1962→
  1963→      // Don't process clicks that are part of a pan gesture
  1964→      // If pointer moved significantly between down and up, this is a pan, not a click
  1965→      if (pointerMovedRef.current) {
  1966→        return;
  1967→      }
  1968→
  1969→      const state = canvasStore.getState();
  1970→
  1971→      const container = containerRef.current;
  1972→      if (!container) return;
  1973→
  1974→      const rect = container.getBoundingClientRect();
  1975→      const camera = state.viewport.camera;
  1976→
  1977→      // Find task at click position
  1978→      const taskId = findTaskAtPosition(
  1979→        e.clientX,
  1980→        e.clientY,
  1981→        rect,
  1982→        camera.x,
  1983→        camera.y,
  1984→        zoom,
  1985→        canvasSize.width,
  1986→        canvasSize.height,
  1987→        tasks
  1988→      );
  1989→
  1990→      if (taskId) {
  1991→        // Toggle selection: if clicking same task, deselect; otherwise, select
  1992→        if (taskId === state.interaction.selectedTaskId) {
  1993→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  1994→        } else {
  1995→          canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
  1996→        }
  1997→      } else {
  1998→        // Clicked on background: clear selection
  1999→        if (state.interaction.selectedTaskId !== null) {
  2000→          canvasStore.dispatch(canvasActions.interaction.clearSelection());
  2001→        }
  2002→      }
  2003→    },
  2004→    [isInitialized, zoom, canvasSize, tasks]
  2005→  );
  2006→
  2007→  /**
  2008→   * Handle pointer leave - clear pan and hover state
  2009→   */
  2010→  const handlePointerLeave = useCallback(
  2011→    (e: React.PointerEvent) => {
  2012→      // Handle pan end
  2013→      handlePointerUp(e);
  2014→      // Clear hover state (F018)
  2015→      canvasStore.dispatch(canvasActions.interaction.clearHover());
  2016→    },
  2017→    [handlePointerUp]
  2018→  );
  2019→
  2020→  // Determine cursor style: grabbing when panning, pointer when hovering task, grab otherwise
  2021→  const cursorStyle = isPanning ? 'grabbing' : isHoverable ? 'pointer' : 'grab';
  2022→
  2023→  // Generate aria-label with current state information (F022)
  2024→  const ariaLabel = `Metro maintenance planning canvas. ${LOD_LABELS[lod]}. ${formatZoomForAria(zoom)}. Use Tab to navigate tasks, Enter to select, Arrow keys to pan, plus minus to zoom.`;
  2025→
  2026→  return (
  2027→    <div
  2028→      ref={containerRef}
  2029→      // F022: ARIA attributes for accessibility
  2030→      role="application"
  2031→      aria-label={ariaLabel}
  2032→      aria-roledescription="Interactive maintenance scheduling canvas"
  2033→      style={{
  2034→        width: '100%',
  2035→        height: '100%',
  2036→        cursor: cursorStyle,
  2037→        touchAction: 'none',
  2038→        position: 'relative', // For absolute positioning of live region
  2039→      }}
  2040→      onPointerDown={handlePointerDown}
  2041→      onPointerMove={handlePointerMove}
  2042→      onPointerUp={handlePointerUp}
  2043→      onPointerLeave={handlePointerLeave}
  2044→      onDoubleClick={handleDoubleClick}
  2045→      onClick={handleClick}
  2046→    >
  2047→      {/* F022: ARIA Live Region for screen reader announcements */}
  2048→      <div
  2049→        ref={ariaLiveRef}
  2050→        role="status"
  2051→        aria-live="polite"
  2052→        aria-atomic="true"
  2053→        style={{
  2054→          position: 'absolute',
  2055→          width: '1px',
  2056→          height: '1px',
  2057→          padding: '0',
  2058→          margin: '-1px',
  2059→          overflow: 'hidden',
  2060→          clip: 'rect(0, 0, 0, 0)',
  2061→          whiteSpace: 'nowrap',
  2062→          border: '0',
  2063→        }}
  2064→      />
  2065→      <Canvas
  2066→        gl={{ antialias: true, alpha: false }}
  2067→        style={{ background: '#f4f4f5' }}
  2068→        orthographic
  2069→        camera={{
  2070→          position: [cameraPos.x, cameraPos.y, 100],
  2071→          zoom: zoom,
  2072→          near: 0.1,
  2073→          far: 1000,
  2074→        }}
  2075→      >
  2076→        <CameraController
  2077→          cameraX={cameraPos.x}
  2078→          cameraY={cameraPos.y}
  2079→          zoom={zoom}
  2080→          worldBounds={worldBounds}
  2081→          isInitialized={isInitialized}
  2082→          onInitialized={handleCameraInitialized}
  2083→          onViewportChange={onViewportChange}
  2084→        />
  2085→
  2086→        <color attach="background" args={['#f4f4f5']} />
  2087→
  2088→        {/* LOD-based layer rendering with smooth transitions */}
  2089→        <LODLayers
  2090→          tasks={tasks}
  2091→          trainCount={trains.length}
  2092→          zoom={zoom}
  2093→          viewportBounds={viewportBounds}
  2094→          spatialIndex={spatialIndex}
